import React from 'react';
import { Link, useParams } from 'react-router-dom';
import { Card, Cards } from '../components/SectionCards';

export default function TopicPage({ content }) {
    const { id } = useParams();
    const section = (content?.sections || []).find(s => s.id === id);

    if (!section) {
        return (
            <div className="container main">
                <div className="error">Topic not found.</div>
                <div style={{ marginTop: 12 }}>
                    <Link className="button" to="/">
                        Back to home
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="container main">
            <div className="section">
                <h1 className="pageTitle">{section.title}</h1>
                {section.body ? <p className="pageBody">{section.body}</p> : null}

                {section.links?.length ? (
                    <>
                        <h2 className="sectionTitle">Links</h2>
                        <Cards>
                            {section.links.map((l, idx) => (
                                <Card key={`${l.label}-${idx}`} title={l.label} linkUrl={l.url} hint="Add a URL in `PythonBackend/content.json`." />
                            ))}
                        </Cards>
                    </>
                ) : null}

                {section.people?.length ? (
                    <>
                        <h2 className="sectionTitle">People</h2>
                        <Cards>
                            {section.people.map((p, idx) => (
                                <Card
                                    key={`${p.name}-${idx}`}
                                    title={p.name}
                                    text={p.role}
                                    linkUrl={p.email ? `mailto:${p.email}` : ''}
                                    linkLabel={p.email || ''}
                                    hint="Add email in `PythonBackend/content.json`."
                                />
                            ))}
                        </Cards>
                    </>
                ) : null}

                {section.flowcharts?.length ? (
                    <>
                        <h2 className="sectionTitle">Flowcharts</h2>
                        <Cards>
                            {section.flowcharts.map((c, idx) => (
                                <Card key={`${c.title}-${idx}`} title={c.title} text={c.description} linkUrl={c.link} hint="Add a link in `PythonBackend/content.json`." />
                            ))}
                        </Cards>
                    </>
                ) : null}

                {section.timeline?.length ? (
                    <>
                        <h2 className="sectionTitle">Timeline</h2>
                        <ul className="list">
                            {section.timeline.map((t, idx) => (
                                <li key={`${t.milestone}-${idx}`} className="listItem">
                                    <div className="listTitle">{t.milestone}</div>
                                    <div className="listText">{t.date || 'TBD'}</div>
                                </li>
                            ))}
                        </ul>
                    </>
                ) : null}
            </div>
        </div>
    );
}
